// Mirrors the logic in src/lib/digestGenerator.js
const STALE_DAYS  = 7;
const RECENT_DAYS = 7;
const now = Date.now();

function msSince(iso) { return iso ? now - new Date(iso).getTime() : Infinity; }
function isRecent(iso) { return msSince(iso) < RECENT_DAYS * 86400000; }
function isStale(iso)  { return msSince(iso) > STALE_DAYS  * 86400000; }
function fmt(iso) { return iso ? new Date(iso).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }) : '—'; }
function lastActivity(eng) {
  const a = eng.notesLog?.slice(-1)[0]?.date;
  const b = eng.outputs?.slice(-1)[0]?.generatedAt;
  return [a, b].filter(Boolean).sort().slice(-1)[0] ?? null;
}

const rows = $input.all();
const all  = rows.flatMap(r => Array.isArray(r.json) ? r.json.map(row => row.data) : [r.json?.data].filter(Boolean));

const active    = all.filter(e => e?.status === 'Active');
const draft     = all.filter(e => e?.status === 'Draft');
const onHold    = all.filter(e => e?.status === 'On Hold');
const completed = all.filter(e => e?.status === 'Completed');

const stale = active.filter(e => isStale(lastActivity(e)));

const highRisks = active.flatMap(e =>
  (e.risksLog ?? []).filter(r => r.status === 'Open' && ['High','Critical'].includes(r.severity))
  .map(r => ({ ...r, engName: e.clientName, company: e.company }))
);

const recentNotes = active.flatMap(e =>
  (e.notesLog ?? []).filter(n => isRecent(n.date)).map(n => ({ ...n, engName: e.clientName }))
).sort((a,b) => b.date.localeCompare(a.date)).slice(0, 5);

const recentOutputs = all.flatMap(e =>
  (e.outputs ?? []).filter(o => isRecent(o.generatedAt)).map(o => ({ ...o, engName: e.clientName }))
);

// Build digest markdown
const today = new Date();
const weekOf = today.toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric', year: 'numeric' });
const lines = [
  '# Weekly Founder Digest',
  '',
  `**Week of:** ${weekOf}`,
  `**Generated:** ${fmt(today.toISOString())}`,
  '',
  '---',
  '',
  '## Engagement Summary',
  '',
  '| Status | Count |',
  '|---|---|',
  `| Active | ${active.length} |`,
  `| Draft | ${draft.length} |`,
  `| On Hold | ${onHold.length} |`,
  `| Completed | ${completed.length} |`,
  `| **Total** | **${all.length}** |`,
  ''
];

if (active.length > 0) {
  lines.push('## Active Engagements', '', '| Client | Workflow Progress |', '|---|---|');
  active.forEach(e => {
    const total = e.workflow?.length ?? 0;
    const done  = e.workflow?.filter(s => s.done).length ?? 0;
    const pct   = total > 0 ? Math.round(done/total*100) : 0;
    lines.push(`| ${e.clientName} | ${done}/${total} (${pct}%) |`);
  });
  lines.push('');
}

if (stale.length > 0) {
  lines.push('## ⚠️ Stale Engagements', '');
  stale.forEach(e => lines.push(`- **${e.clientName}** (${e.company}) — last activity: ${fmt(lastActivity(e))}`));
  lines.push('');
}

if (highRisks.length > 0) {
  lines.push('## 🔴 Open High / Critical Risks', '');
  highRisks.forEach(r => lines.push(`- **[${r.severity}]** ${r.title} — _${r.engName}_`));
  lines.push('');
}

if (recentNotes.length > 0) {
  lines.push('## Recent Notes', '');
  recentNotes.forEach(n => {
    const preview = n.content.length > 120 ? n.content.slice(0,120)+'…' : n.content;
    lines.push(`- **${n.engName}** (${fmt(n.date)}): ${preview}`);
  });
  lines.push('');
}

lines.push('---', '*Generated by Barinhall Delivery Hub*');

const digest = lines.join('\n');

return [{
  json: {
    digest,
    subject:      `Barinhall Weekly Digest — ${fmt(today.toISOString())}`,
    to:           $env.FOUNDER_EMAIL,
    from:         $env.SENDER_EMAIL,
    summary: {
      totalEngagements: all.length,
      activeCount:      active.length,
      draftCount:       draft.length,
      staleCount:       stale.length,
      openHighRisks:    highRisks.length,
      recentOutputsCount: recentOutputs.length
    }
  }
}];
